&#123;				append_sendbuffer_udp(ss,s,priority,request,udp_address);			&#125; else &#123;				stat_write(ss,s,n);				so.free_func(request-&gt;buffer);				return -1;			&#125;		&#125;		sp_write(ss-&gt;event_fd, s-&gt;fd, s, true);	// 监听写就绪事件	&#125; else &#123;		// 正常的可以直接发送的socket		if (s-&gt;protocol == PROTOCOL_TCP) &#123;			// 如果是tcp，按照队列优先级添加			if (priority == PRIORITY_LOW) &#123;				append_sendbuffer_low(ss, s, request);			&#125; else &#123;				append_sendbuffer(ss, s, request);			&#125;		&#125; else &#123;			if (udp_address == NULL) &#123;				udp_address = s-&gt;p.udp_address;			&#125;			append_sendbuffer_udp(ss,s,priority,request,udp_address);		&#125;	&#125;	// 如果发送的包太大，则报一个警告	if (s-&gt;wb_size &gt;= WARNING_SIZE &amp;&amp; s-&gt;wb_size &gt;= s-&gt;warn_size) &#123;		s-&gt;warn_size = s-&gt;warn_size == 0 ? WARNING_SIZE *2 : s-&gt;warn_size*2;		result-&gt;opaque = s-&gt;opaque;		result-&gt;id = s-&gt;id;		result-&gt;ud = s-&gt;wb_size%1024 == 0 ? s-&gt;wb_size/1024 : s-&gt;wb_size/1024 + 1;		result-&gt;data = NULL;		return SOCKET_WARNING;	&#125;	return -1;&#125;// 发送对象初始化static inline boolsend_object_init(struct socket_server *ss, struct send_object *so, void *object, int sz) &#123;	if (sz &lt; 0) &#123;		so-&gt;buffer = ss-&gt;soi.buffer(object);		so-&gt;sz = ss-&gt;soi.size(object);		so-&gt;free_func = ss-&gt;soi.free;		return true;	&#125; else &#123;		so-&gt;buffer = object;		so-&gt;sz = sz;		so-&gt;free_func = FREE;		return false;	&#125;&#125;// 添加到发送队列static inline voidappend_sendbuffer(struct socket_server *ss, struct socket *s, struct request_send * request) &#123;	struct write_buffer *buf = append_sendbuffer_(ss, &amp;s-&gt;high, request, SIZEOF_TCPBUFFER);	s-&gt;wb_size += buf-&gt;sz;&#125;static struct write_buffer *append_sendbuffer_(struct socket_server *ss, struct wb_list *s, struct request_send * request, int size) &#123;	struct write_buffer * buf = MALLOC(size);	struct send_object so;	buf-&gt;userobject = send_object_init(ss, &amp;so, request-&gt;b