static intlcommand(lua_State *L) &#123;    struct skynet_context * context = lua_touserdata(L, lua_upvalueindex(1));    const char * cmd = luaL_checkstring(L,1);    const char * result;    const char * parm = NULL;    if (lua_gettop(L) == 2) &#123;        parm = luaL_checkstring(L,2);    &#125;        // 这里就是调用skynet_server.c    result = skynet_command(context, cmd, parm);    if (result) &#123;        lua_pushstring(L, result);        return 1;    &#125;    return 0;&#125;

也就最后调用到skynet_server.c中skynet_command
static struct command_func cmd_funcs[] = &#123;    &#123; &quot;TIMEOUT&quot;, cmd_timeout &#125;,    &#123; &quot;REG&quot;, cmd_reg &#125;,    &#123; &quot;QUERY&quot;, cmd_query &#125;,    &#123; &quot;NAME&quot;, cmd_name &#125;,    &#123; &quot;EXIT&quot;, cmd_exit &#125;,    &#123; &quot;KILL&quot;, cmd_kill &#125;,    &#123; &quot;LAUNCH&quot;, cmd_launch &#125;, //LAUNCH对应这个    &#123; &quot;GETENV&quot;, cmd_getenv &#125;,    &#123; &quot;SETENV&quot;, cmd_setenv &#125;,    &#123; &quot;STARTTIME&quot;, cmd_starttime &#125;,    &#123; &quot;ABORT&quot;, cmd_abort &#125;,    &#123; &quot;MONITOR&quot;, cmd_monitor &#125;,    &#123; &quot;STAT&quot;, cmd_stat &#125;,    &#123; &quot;LOGON&quot;, cmd_logon &#125;,    &#123; &quot;LOGOFF&quot;, cmd_logoff &#125;,    &#123; &quot;SIGNAL&quot;, cmd_signal &#125;,    &#123; NULL, NULL &#125;,&#125;;const char * skynet_command(struct skynet_context * context, const char * cmd , const char * param) &#123;    struct command_func * method = &amp;cmd_funcs[0];    while(method-&gt;name) &#123;        if (strcmp(cmd, method-&gt;name) == 0) &#123;            return method-&gt;func(context, param);        &#125;        ++method;    &#125;    return NULL;&#125;

再看到cmd_launch，这里就十分熟悉了，接入回上面的bootstrap的分析
static const char *cmd_launch(struct skynet_context * context, const char * param) &#123;    size_t sz = strlen(param);    char tmp[sz+1];    strcpy(tmp,param);    char * args = tmp;    char * mod = strsep(&amp;args, &quot; \t\r\n&quot;);    args = strsep(&amp;args, &quot;\r\n&quot;);        // 这里这几行是不是特别熟悉        // 没错，就是和上面的bootstrap的启动一模一样        // 就是使用snlua去启动另外的服务    struct skynet_context * inst = skynet_context_new(mod,args);    if (inst == NULL) &#123;        return NULL;    &#125; else &#123;        id_to_hex(context-&gt;result, inst-&gt;handle);        return context-&gt;result;    &#125;&#125;

可以看到，之后我们在lua层使用的skynet.newservice都是通过launcher.lua去启动新服务器的了。
最后bootstrap做的事情中一个重要就是，启动了launcher.lua服务，之后框架中skynet.newservice就是调用launcher去启动lua服务。
所以叫他服务器的前置任务。之后的启动新服务之后，回调函数怎么挂钩之类的，之后在分析。
